@Composable
fun ItemList(items: List<Item>, viewModel: ItemViewModel) {
    LazyColumn {
        items(items, key = { it.id }) { item ->
            val onFavorite = remember(item.id) { { viewModel.toggleFavorite(item.id) } }
            val onDelete = remember(item.id) { { viewModel.deleteItem(item.id) } }
            ItemRow(item = item, onFavorite = onFavorite, onDelete = onDelete)
        }
    }
}

